const now = new Date();
const ytdStart = new Date(Date.UTC(now.getUTCFullYear(), 0, 1));
const days60 = new Date(now.getTime() - 60 * 86400 * 1000);
days60.setUTCHours(0, 0, 0, 0);
const todayEnd = new Date(now);
todayEnd.setUTCHours(23, 59, 59, 999);
return [{ json: {
  ytd_start_ms: String(ytdStart.getTime()),
  days60_ms: String(days60.getTime()),
  today_end_ms: String(todayEnd.getTime()),
  ytd_start_date: ytdStart.toISOString().slice(0, 10),
  days60_date: days60.toISOString().slice(0, 10),
  today_date: now.toISOString().slice(0, 10)
} }];

const bqDealsRows = $('BQ Deals').all().map(i => i.json);
const bqLeadsRows = $('BQ Leads').all().map(i => i.json);

const bqDealsTotal = bqDealsRows.reduce((s, r) => s + Number(r.deals || 0), 0);
const bqLeadsTotal = bqLeadsRows.reduce((s, r) => s + Number(r.leads || 0), 0);

const hsDealsTotal = Number($('HS Deals').first().json.total || 0);
const hsLeadsTotal = Number($('HS Leads').first().json.total || 0);

const dealsRate = hsDealsTotal > 0 ? Math.round(bqDealsTotal / hsDealsTotal * 100) : null;
const leadsRate = hsLeadsTotal > 0 ? Math.round(bqLeadsTotal / hsLeadsTotal * 100) : null;

const today = $('Set Dates').first().json.today_date;
const ytdStart = $('Set Dates').first().json.ytd_start_date;
const days60 = $('Set Dates').first().json.days60_date;

const fmt = (rate, bq, hs) => {
  if (rate === null) return `⚠️ HS error | BQ ${bq.toLocaleString()}`;
  const icon = rate >= 85 ? '✅' : '❌';
  return `${icon} ${rate}%  BQ ${bq.toLocaleString()} / HS ${hs.toLocaleString()}`;
};

let msg = `📊 *Data Health — ${today}*\n`;
msg += `Deals (${ytdStart} → today, paid): ${fmt(dealsRate, bqDealsTotal, hsDealsTotal)}\n`;
msg += `Leads (${days60} → today): ${fmt(leadsRate, bqLeadsTotal, hsLeadsTotal)}`;

if ((dealsRate !== null && dealsRate < 85) || (leadsRate !== null && leadsRate < 85)) {
  msg += `\n_Gap detected — next collector run (≤6h via GitHub Actions) will auto-backfill._`;
}

return [{ json: { text: msg } }];
